return items.map(item => {
  let data = item.json;

  // 1️⃣ Trim all string fields
  for (let key in data) {
    if (typeof data[key] === "string") {
      data[key] = data[key].trim();
    }
  }

  // 2️⃣ Standardize text case
  if (data.gender) {
    data.gender = data.gender.toLowerCase();
  }

  if (data.contract) {
    data.contract = data.contract.toLowerCase();
  }

  // 3️⃣ Convert numeric fields
  if (data.tenure) {
    data.tenure = Number(data.tenure);
  }

  if (data.monthlycharges) {
    data.monthlycharges = Number(data.monthlycharges);
  }

  if (data.churn_percentage) {
    data.churn_percentage = Number(data.churn_percentage);
  }

  // 4️⃣ Handle missing values
  if (!data.tenure || isNaN(data.tenure)) {
    data.tenure = 0;
  }

  if (!data.monthlycharges || isNaN(data.monthlycharges)) {
    data.monthlycharges = 0;
  }

  // 5️⃣ Remove impossible values
  if (data.tenure < 0) {
    data.tenure = 0;
  }

  if (data.monthlycharges < 0) {
    data.monthlycharges = 0;
  }

  // 6️⃣ Validate email
  if (data.email) {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(data.email)) {
      data.email_valid = false;
    } else {
      data.email_valid = true;
    }
  }

  // 7️⃣ Create feature: high_value_customer
  data.high_value_customer = data.monthlycharges > 100;

  return { json: data };
});

return items.map(item => {

  // 1️⃣ Extract values
  let tenure = Number(item.json.tenure) || 0;
  let monthly = Number(item.json.MonthlyCharges) || 0;
  let contract = item.json.Contract;
  let security = item.json.OnlineSecurity;
  let tech = item.json.TechSupport;

  // 2️⃣ Encode categorical variables

  // Contract encoding
  let contract_num = 0;
  if (contract === "Month-to-month") contract_num = 0;
  else if (contract === "One year") contract_num = 1;
  else if (contract === "Two year") contract_num = 2;

  // Online security (Yes=1, No=0)
  let security_num = (security === "Yes") ? 1 : 0;

  // Tech support (Yes=1, No=0)
  let tech_num = (tech === "Yes") ? 1 : 0;

  // 3️⃣ Logistic Regression Coefficients (realistic example)
  let intercept = -1.5;
  let b_tenure = -0.03;
  let b_monthly = 0.02;
  let b_contract = -0.6;
  let b_security = -0.8;
  let b_tech = -0.7;

  // 4️⃣ Linear combination
  let z = intercept
          + (b_tenure * tenure)
          + (b_monthly * monthly)
          + (b_contract * contract_num)
          + (b_security * security_num)
          + (b_tech * tech_num);

  // 5️⃣ Sigmoid function
  let probability = 1 / (1 + Math.exp(-z));

  return {
    json: {
      ...item.json,
      churn_probability: probability,
      churn_percentage: (probability * 100).toFixed(2)
    }
  };
});

const items = $input.all();

for (let item of items) {

    let tenure = Number(item.json.tenure) || 0;
    let monthly = Number(item.json.MonthlyCharges) || 0;
    let contract = item.json.Contract || "";

    let contract_flag = contract === "Month-to-month" ? 1 : 0;

    let w_tenure = -0.05;
    let w_monthly = 0.03;
    let w_contract = 1.2;
    let bias = -1.5;

    let z =
        (w_tenure * tenure) +
        (w_monthly * monthly) +
        (w_contract * contract_flag) +
        bias;

    let probability = 1 / (1 + Math.exp(-z));

    item.json.churn_percentage = Math.round(probability * 100);
}

return items;
